mapper.select:
SELECT tc.id AS contactId, tc.enterprise_id AS enterpriseId, tc.student_id AS studentId, tc.source_type AS sourceType, tc.application_id AS applicationId, tc.job_id AS jobId, jp.job_title AS jobTitle, tc.name AS name, tc.phone AS phone, tc.email AS email, tc.wechat AS wechat, tc.position AS position, CASE WHEN UPPER(IFNULL(tc.status, '')) = 'INACTIVE' THEN 'INACTIVE' ELSE 'ACTIVE' END AS status, tc.latest_status AS latestStatus, tc.last_contact_time AS latestCommunicationTime, tc.remark AS remark, tc.created_time AS createdTime, tc.updated_time AS updatedTime FROM talent_contact tc LEFT JOIN job_posting jp ON jp.id = tc.job_id WHERE tc.enterprise_id = #{enterpriseId}
AND tc.student_id = #{studentId}
AND tc.application_id = #{applicationId}
AND tc.job_id = #{jobId}
AND tc.source_type = #{sourceType}
AND UPPER(IFNULL(tc.status, '')) = 'INACTIVE'
AND UPPER(IFNULL(tc.status, 'ACTIVE')) != 'INACTIVE'
AND ( tc.name LIKE CONCAT('%', #{keyword}, '%') OR tc.phone LIKE CONCAT('%', #{keyword}, '%') OR tc.email LIKE CONCAT('%', #{keyword}, '%') OR tc.wechat LIKE CONCAT('%', #{keyword}, '%') OR tc.position LIKE CONCAT('%', #{keyword}, '%') OR jp.job_title LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY tc.last_contact_time DESC, tc.updated_time DESC, tc.id DESC

SELECT *
FROM talent_contact
WHERE enterprise_id = #{enterpriseId}
  AND id = #{id}
LIMIT 1

SELECT *
FROM talent_contact
WHERE enterprise_id = #{enterpriseId}
  AND application_id = #{applicationId}
LIMIT 1

SELECT COUNT(1)
FROM talent_contact
WHERE enterprise_id = #{enterpriseId}

mapper.delete:
DELETE FROM talent_contact
WHERE enterprise_id = #{enterpriseId}
  AND id = #{id}
